#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Источник истины для набора E2E-примеров pravo-grammatika.

Запуск:  python build_cases.py   →  пишет cases.jsonl рядом.

Каждый пример — это вход (условный правовой текст на русском), режим скилла и
ожидаемый результат: конкретный дефект ФОРМЫ ВЫРАЖЕНИЯ (с именем и списком
синонимов-алиасов для грейдинга) либо `clean` — формулировка однозначна / норма
языка не нарушена, где скилл НЕ должен выдумывать второе прочтение.

Скилл проверяет ФОРМУ (однозначность), а не валидность вывода (это pravo-logika),
не убедительность подачи (pravo-ritorika) и не право по существу. Все примеры
условны: реальные нормы и дела не воспроизводятся (инвариант скилла).

Разделы (по первой букве id):
  A — синтаксическая неоднозначность: последний антецедент, присоединение оборота
      и предложной группы, родительная цепочка, эллипсис, косящее обстоятельство;
  P — пунктуация, меняющая смысл: обособление, тире, двоеточие, скобки, точка с запятой;
  S — область действия: «и/или», перечень без статуса, «в том числе»/«включая, но не
      ограничиваясь», отрицание над рядом, изъятие, границы сроков;
  R — отсылки и анафора: местоимение, «соответствующий», «настоящий», внутренние
      ссылки, согласованность терминов;
  M — модальность: вправе/обязан, «должен», «может», отрицания, носитель обязанности;
  O — нормы языка: управление, согласование, висящий оборот, числа, сроки, диапазоны;
  W — переписывание: закрепление прочтения / два варианта под выбор автора;
  K — сделки и корпоративные сценарии (право РФ; форма на материале практики);
  N — корректные примеры (форма однозначна) — ловят выдуманное второе прочтение.
"""
import json
import os

# Схема записи:
#   id, mode (ambiguity|punctuation|norm|rewrite), category, difficulty (easy|medium|hard),
#   input, expect (defect|clean),
#   defect_ru, defect_lat, aliases[] (для expect=defect), why
CASES = []


def d(id, mode, category, difficulty, input, expect,
      defect_ru="", defect_lat="", aliases=None, why=""):
    CASES.append({
        "id": id, "mode": mode, "category": category, "difficulty": difficulty,
        "input": input, "expect": expect,
        "defect_ru": defect_ru, "defect_lat": defect_lat,
        "aliases": aliases or [], "why": why,
    })


